server {
    listen 80;
    server_name _;
    root /usr/share/nginx/html;
    index index.html;

    # Next static export writes /use-cases.html (not /use-cases/index.html).
    # $uri.html serves it directly for extensionless routes — no dir redirect,
    # so no 301 (which also dropped https→http behind Cloudflare).
    location / {
        try_files $uri $uri.html $uri/ =404;
    }

    error_page 404 /404.html;
}

